module timer_core #(
    parameter integer DATA_WIDTH = 32,
    parameter integer ADDR_WIDTH = 4
) (
    input  logic                  pclk,
    input  logic                  presetn,
    input  logic [DATA_WIDTH-1:0] load_q,
    input  logic                  enable_q,
    output logic [DATA_WIDTH-1:0] count_q,
    output logic                  irq
);

    localparam [1:0] DISABLED      = 2'd0,
                     ENABLED_COUNT = 2'd1,
                     RELOAD_IRQ    = 2'd2;

    logic [1:0] timer_state_q;
    logic [1:0] timer_state_d;
    logic       zero_count;
    logic       tick_decrement;
    logic       tick_reload_irq;
    logic       disabled_hold;

    assign zero_count      = (count_q == {DATA_WIDTH{1'b0}});
    assign tick_decrement  = enable_q & ~zero_count;
    assign tick_reload_irq = enable_q & zero_count;
    assign disabled_hold   = ~enable_q;

    always @(*) begin
        timer_state_d = timer_state_q;
        case (timer_state_q)
            DISABLED: begin
                if (enable_q) begin
                    timer_state_d = ENABLED_COUNT;
                end
            end
            ENABLED_COUNT: begin
                if (!enable_q) begin
                    timer_state_d = DISABLED;
                end else if (zero_count) begin
                    timer_state_d = RELOAD_IRQ;
                end
            end
            RELOAD_IRQ: begin
                if (!enable_q) begin
                    timer_state_d = DISABLED;
                end else begin
                    timer_state_d = ENABLED_COUNT;
                end
            end
            default: begin
                timer_state_d = DISABLED;
            end
        endcase
    end

    always @(posedge pclk or negedge presetn) begin
        if (!presetn) begin
            timer_state_q <= DISABLED;
            count_q       <= {DATA_WIDTH{1'b0}};
            irq           <= 1'b0;
        end else begin
            timer_state_q <= timer_state_d;

            if (disabled_hold) begin
                count_q <= count_q;
                irq     <= 1'b0;
            end else if (tick_decrement) begin
                count_q <= count_q - {{(DATA_WIDTH-1){1'b0}}, 1'b1};
                irq     <= 1'b0;
            end else if (tick_reload_irq) begin
                count_q <= load_q;
                irq     <= 1'b1;
            end else begin
                count_q <= count_q;
                irq     <= 1'b0;
            end
        end
    end

endmodule

